/**
 * Server-side persistent operation hook.
 *
 * Operations are processed by the Railway worker (apps/worker), which polls
 * admin_config.BULK_OPERATIONS every 5 seconds. The UI just writes "running"
 * state and polls for progress — no client-side batch loops required.
 */

export interface OperationProgress {
  [key: string]: unknown;
}

export interface OperationState {
  status: "idle" | "running" | "completed" | "completed_with_repair" | "failed" | "interrupted" | "queued";
  cursor?: number;
  params?: Record<string, unknown>;
  started_at?: string;
  updated_at?: string;
  progress?: OperationProgress;
  result_message?: string;
  error?: string;
  // Enhanced fields
  interruption_reason_code?: string;
  auto_resume_attempts?: number;
  run_id?: string;
  last_stage?: string;
  last_substage?: string;
  queue_position?: number;
}

const CONFIG_KEY = "BULK_OPERATIONS"; // used for polling reads only
const POLL_ACTIVE_MS = 3_000;
const POLL_IDLE_MS = 30_000;

export function usePersistentOperation(operationKey: string) {
  const { call } = useAdminApi();
  const [state, setState] = useState<OperationState>({ status: "idle" });
