  useEffect(() => {
    let mounted = true;
    let timerId: ReturnType<typeof setTimeout>;
    let currentStatus = "idle";
    let firstPoll = true;

    const poll = async () => {
      try {
        const data = await call("get-config", { keys: [CONFIG_KEY] });
        if (!mounted) return;
        const ops = (
          data?.config?.[CONFIG_KEY]?.value ?? data?.config?.[CONFIG_KEY]
        ) as Record<string, OperationState> | undefined;
        const saved = ops?.[operationKey];
        if (saved) {
          setState(saved);
          currentStatus = saved.status;
        } else {
          setState({ status: "idle" });
          currentStatus = "idle";
        }
        consecutiveFailures.current = 0;
      } catch (e) {
        consecutiveFailures.current += 1;
        if (consecutiveFailures.current >= CONSECUTIVE_FAILURE_WARN_THRESHOLD) {
          console.error(
            `usePersistentOperation[${operationKey}]: ${consecutiveFailures.current} consecutive poll failures`,
            e,
          );
        }
      }

      if (firstPoll) {
        firstPoll = false;
        if (mounted) setIsHydrating(false);
      }

      if (!mounted) return;
      timerId = setTimeout(
        poll,
        currentStatus === "running" || currentStatus === "queued" ? POLL_ACTIVE_MS : POLL_IDLE_MS,
      );
    };

    poll();
    return () => {
      mounted = false;
      clearTimeout(timerId);
    };
  }, [operationKey]); // eslint-disable-line react-hooks/exhaustive-deps

  // ── Atomic persist via update-bulk-op RPC ────────────────────────
  const persistState = useCallback(
    async (opState: OperationState) => {
      try {
        await call("update-bulk-op", {
          op_key: operationKey,
          op_state: opState,
        });
      } catch {
        // best-effort
      }
    },
    [call, operationKey],
  );

  // ── Start a server-side operation ───────────────────────────────
  const start = useCallback(
    async (options?: {
      confirmMessage?: string;
      params?: Record<string, unknown>;
      initialProgress?: OperationProgress;
      forceRestart?: boolean;
    }) => {
      // Allow force restart even when running
