import { createClient } from "https://esm.sh/@supabase/supabase-js@2";

const corsHeaders = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type, x-smoke-key",
};

Deno.serve(async (req) => {
  if (req.method === "OPTIONS") return new Response(null, { headers: corsHeaders });
  const expected = Deno.env.get("PROD_ORDER_SMOKE_KEY");
  if (!expected || req.headers.get("x-smoke-key") !== expected) {
    return new Response(JSON.stringify({ ok: false, error: "unauthorized" }), {
      status: 401,
      headers: { ...corsHeaders, "Content-Type": "application/json" },
    });
  }

  const supabaseUrl = Deno.env.get("SUPABASE_URL")!;
  const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY")!;
  const adminResp = await fetch(`${supabaseUrl}/functions/v1/admin-api`, {
    method: "POST",
    headers: {
      "Authorization": `Bearer ${serviceRoleKey}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify({ action: "trigger-prod-order-sync" }),
  });
  const adminText = await adminResp.text();
  let adminResult: unknown = adminText;
  try {
    adminResult = JSON.parse(adminText);
  } catch {
    // Keep text.
  }

  const db = createClient(supabaseUrl, serviceRoleKey);
  const [{ count: currentRows }, { count: rawRows }, { data: latestRun }] = await Promise.all([
    db.from("prod_order_headers_current").select("id", { count: "exact", head: true }),
    db.from("prod_order_headers_raw").select("id", { count: "exact", head: true }),
    db.from("prod_order_sync_runs")
      .select("status, total_fetched, total_upserted, total_errors, error_samples, started_at, ended_at")
      .order("started_at", { ascending: false })
      .limit(1)
      .maybeSingle(),
  ]);

  return new Response(JSON.stringify({
    ok: adminResp.ok,
    admin_status: adminResp.status,
    admin_result: adminResult,
    current_rows: currentRows ?? 0,
    raw_rows: rawRows ?? 0,
    latest_run: latestRun ?? null,
  }), {
    status: 200,
    headers: { ...corsHeaders, "Content-Type": "application/json" },
  });
});

